export function getRulesForSection(sectionNumber: number): CodifiedRule[] {
  const prefix = `Section ${sectionNumber}`;
  return CODIFIED_RULES.filter(r => r.source.startsWith(prefix) || r.source === prefix);
}

export function getRulesForChapter(chapterNumber: number): CodifiedRule[] {
  const padded = `Chapter ${String(chapterNumber).padStart(2, '0')}`;
  return CODIFIED_RULES.filter(r => r.source.startsWith(padded) || r.source === padded);
}

export function getExclusionRules(source: string): CodifiedRule[] {
  return CODIFIED_RULES.filter(r => r.source.startsWith(source) && r.type === 'exclusion');
}

export function getInclusionRules(source: string): CodifiedRule[] {
  return CODIFIED_RULES.filter(r => r.source.startsWith(source) && r.type === 'inclusion');
}

export function getNumericRules(source: string): CodifiedRule[] {
  return CODIFIED_RULES.filter(r => r.source.startsWith(source) && r.type === 'numeric_threshold');
}

export function getMaterialRules(source: string): CodifiedRule[] {
  return CODIFIED_RULES.filter(r => r.source.startsWith(source) && r.type === 'material_condition');
}

/**
 * Phrase-based exclusion matching (v2 — fixes false positives like "cotton" vs "cotton linters").
 *
 * Strategy:
 * 1. Extract key noun phrases from rule text (2-3 word phrases)
 * 2. Check if ANY phrase appears in input (phrase match > keyword overlap)
 * 3. If rule references a specific heading/chapter number, require that number context
 * 4. Threshold: at least 1 phrase match OR 5+ individual keyword matches
 */
export function matchExclusion(inputText: string, rules: CodifiedRule[]): { matched: boolean; redirect?: { type: string; target: string }; rule?: CodifiedRule } {
  const text = inputText.toLowerCase();
  const exclusions = rules.filter(r => r.type === 'exclusion');

  for (const rule of exclusions) {
    const ruleText = (rule.original_text || '').toLowerCase();
    if (!ruleText || ruleText.length < 10) continue;

    // 1. Extract key phrases (noun phrases from the rule)
    const phrases = extractKeyPhrases(ruleText);

    // 2. Check phrase matches
    const phraseMatch = phrases.some(phrase => text.includes(phrase));

    // 3. Fallback: high keyword overlap (5+ meaningful words)
    const stopWords = new Set(['this','that','with','from','have','been','they','their','which','shall','other','under','heading','chapter','section','classified','articles','goods','products','parts','thereof']);
    const ruleWords = ruleText.split(/\s+/).filter(w => w.length > 3 && !stopWords.has(w));
    const matchCount = ruleWords.filter(w => text.includes(w)).length;
    const highOverlap = matchCount >= 5;

    if ((phraseMatch || highOverlap) && rule.action) {
      const target = rule.action.target_headings?.[0] ||
                     rule.action.target_chapters?.[0]?.toString() ||
                     rule.action.target_sections?.[0] || '';
      return { matched: true, redirect: { type: rule.action.type, target }, rule };
    }
  }

  return { matched: false };
}

/** Check if input matches any inclusion rule */
export function matchInclusion(inputText: string, rules: CodifiedRule[]): { matched: boolean; target?: string; rule?: CodifiedRule } {
  const text = inputText.toLowerCase();
  const inclusions = rules.filter(r => r.type === 'inclusion');

  for (const rule of inclusions) {
    const ruleText = (rule.original_text || '').toLowerCase();
    if (!ruleText || ruleText.length < 10) continue;

    const phrases = extractKeyPhrases(ruleText);
    const phraseMatch = phrases.some(phrase => text.includes(phrase));

    const stopWords = new Set(['this','that','with','from','have','been','they','their','which','shall','other','under','heading','chapter','section','classified','articles','goods','products','parts','thereof']);
    const ruleWords = ruleText.split(/\s+/).filter(w => w.length > 3 && !stopWords.has(w));
    const matchCount = ruleWords.filter(w => text.includes(w)).length;

    if (phraseMatch || matchCount >= 5) {
      const target = rule.action?.target_heading || '';
      return { matched: true, target, rule };
    }
  }

  return { matched: false };
}

/** Extract key noun phrases (2-3 words) from rule text */
function extractKeyPhrases(text: string): string[] {
  const phrases: string[] = [];
  // Known compound terms that must match as phrases
  const knownPhrases = [
    'cotton linters', 'horsehair yarn', 'human hair', 'artificial straw',
    'glass fibres', 'carbon fibres', 'glass thread', 'silk worm gut',
    'precious metal', 'base metal', 'ferro-cerium', 'pyrophoric alloys',
    'rubber belt', 'transmission belt', 'conveyor belt',
    'perforated cards', 'paper yarn', 'metal thread',
    'drill pipe', 'endless belts', 'sensitised textiles',
    'clock springs', 'watch springs', 'dental floss',
    'electric motor', 'nuclear reactor', 'printed circuit',
    'assembled railway', 'tramway track', 'lead shot',
    'interchangeable tools', 'typewriter ribbons',
    'precious stones', 'semi-precious stones', 'imitation jewellery',
    'motor vehicle', 'road vehicle', 'air-cushion vehicle',
  ];
  for (const kp of knownPhrases) {
    if (text.includes(kp)) phrases.push(kp);
  }

  // Also extract "X of heading XXXX" patterns as heading-specific phrases
  const headingRefs = text.match(/(?:of\s+)?heading\s+(\d{2}\.?\d{2})/g);
  if (headingRefs) {
    for (const ref of headingRefs) {
      phrases.push(ref);
    }
  }

  return phrases;
}
